#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <signal.h>
main(){
int bayrak =1;
pid_t pid;
pid = fork();
if (pid == 0){
while (bayrak){
printf("Çocuk proses çalışıyor...\n");
}
printf("Çocuk proses işini bitirdi...\n");
}
else{               sleep(1);
kill(pid, SIGSTOP);
printf("\nAnne proses çalışıyor...\n");
